}' --jq '.data.repository.pullRequest.reviewThreads.nodes[] | select(.isResolved == false) | select(.comments.nodes[0].author.login | test("copilot-pull-request-reviewer|Copilot")) | .comments.nodes[0].databaseId'
        if ($unresolved) { Write-Host "UNRESOLVED: $unresolved" } else { Write-Host "NO NEW COMMENTS - ALL CLEAR!" }
        break
    }

    Write-Host "Waiting... ($elapsed sec)"
    Start-Sleep -Seconds $interval
    $elapsed += $interval
}

if ($elapsed -ge $timeout) { Write-Host "TIMEOUT" }
